import ast

def audit_error_handling(code: str) -> dict:
    tree = ast.parse(code)
    try_blocks = 0
    for node in ast.walk(tree):
        if isinstance(node, ast.Try):
            try_blocks += 1

    return {
        'has_error_handling': try_blocks > 0,
        'try_blocks': try_blocks,
        'score': min(try_blocks * 10, 100)
    }

