from smolagents import Tool

SAFE_TOOLS = {'search', 'calculate', 'read_file'}
DANGEROUS_TOOLS = {'delete', 'write_file', 'exec'}

def validate_tool_call(tool_name: str, args: dict) -> bool:
    if tool_name in DANGEROUS_TOOLS:
        print(f"BLOCKED: Dangerous tool {tool_name}")
        return False

    if any(arg in args for arg in ['rm', 'del', 'drop', 'truncate']):
        print(f"BLOCKED: Dangerous args in {tool_name}")
        return False

    return True

# Usage in agent
